module.exports = async function (context, req) {
    const { CosmosClient } = require("@azure/cosmos");
    const client = new CosmosClient(process.env.COSMOSDB_CONNECTION_STRING);
    const database = client.database(process.env.DATABASE_NAME);
    const container = database.container(process.env.CONTAINER_NAME);
    
    context.log('Starting batch processing function');
    
    // Set timeout to maximum (600000 ms = 10 minutes)
    const maxTimeout = 600000;
    const startTime = Date.now();
    
    try {
        // Disable timeout enforcement where possible
        context.executionContext.setIsolated(false);
        
        // Query large dataset
        const query = {
            query: "SELECT * FROM c WHERE c.processed = false",
            parameters: []
        };
        
        const { resources: items } = await container.query(query, { 
            maxItemCount: 1000,
            enableCrossPartitionQuery: true
        }).fetchAll();
        
        context.log(`Found ${items.length} items to process`);
        
        // Process items in batches
        const batchSize = 100;
        for (let i = 0; i < items.length; i += batchSize) {
            const batch = items.slice(i, i + batchSize);
            
            // Check if we're close to timeout
            if (Date.now() - startTime > maxTimeout - 10000) {
                context.log('Approaching timeout, queuing next execution');
                break;
            }
            
            // Process batch
            await processBatch(batch, container);
        }
        
        context.log('Batch processing completed successfully');
        context.res = {
            status: 200,
            body: { message: 'Batch processing completed', processed: items.length }
        };
        
    } catch (error) {
        context.log.error('Error in batch processing:', error);
        context.res = {
            status: 500,
            body: { error: error.message }
        };
    }
};

async function processBatch(batch, container) {
    // Process each item in the batch
    const operations = [];
    
    for (const item of batch) {
        // Simulate processing logic
        const processedItem = {
            ...item,
            processed: true,
            processedAt: new Date().toISOString()
        };
        
        operations.push({
            operationType: "Replace",
            resource: processedItem
        });
    }
    
    // Execute batch operations
    if (operations.length > 0) {
        await container.batch(operations);
    }
}